#include<bits/stdc++.h>
using namespace std;
int n,d,a[100005],b[100005],minn=0x3f3f3f3f;
long long ans=0,km=0;
int main()
{
    cin>>n>>d;
    for(int i=1;i<n;i++) cin>>a[i];
    for(int i=1;i<=n;i++) cin>>b[i];
    for(int i=1;i<n;i++)
    {
        minn=min(minn,b[i]);
        if(km>=a[i]) km-=a[i];
        else
        {
            long long money=minn*ceil((double)(a[i]-km)/d);
            ans+=money;
            km=money/minn*d-(a[i]-km);
        }
    }
    cout<<ans;
    return 0;
}
